const webhook = $('Quality Gate Webhook').first().json;
return [{
  json: {
    businessId: webhook.body.businessId,
    businessName: webhook.body.businessName,
    siteUrl: webhook.body.siteUrl,
    repoName: webhook.body.repoName
  }
}];

// Parse Lighthouse results
const lighthouseRaw = $('Lighthouse Check').first().json;
let lighthouse = { performance: null, accessibility: null, seo: null, error: null };
try {
  if (lighthouseRaw.lighthouseResult) {
    const cats = lighthouseRaw.lighthouseResult.categories;
    lighthouse.performance = Math.round((cats.performance?.score || 0) * 100);
    lighthouse.accessibility = Math.round((cats.accessibility?.score || 0) * 100);
    lighthouse.seo = Math.round((cats.seo?.score || 0) * 100);
  } else {
    lighthouse.error = lighthouseRaw.error?.message || 'Lighthouse returned no results';
  }
} catch (e) {
  lighthouse.error = 'Failed to parse Lighthouse response: ' + e.message;
}

return [{ json: { lighthouse } }];

const fetchResult = $('Fetch Site HTML').first().json;
const html = (fetchResult.body || fetchResult.data || '').toString().toLowerCase();
const checks = [];

if (!html || html.length < 100) {
  return [{ json: { slopChecks: [{ check: 'Site Reachable', pass: false, detail: 'Could not fetch site HTML or response too short' }], seoChecks: [] } }];
}

// --- Slop / Placeholder content checks ---
const slopPatterns = [
  { name: 'Lorem Ipsum', pattern: 'lorem ipsum' },
  { name: 'example.com link', pattern: 'example.com' },
  { name: '"Your Company" placeholder', pattern: 'your company' },
  { name: 'Placeholder text', pattern: 'placeholder' },
  { name: '[insert...] template', pattern: '[insert' },
  { name: 'TODO marker', pattern: 'todo' }
];

const slopChecks = slopPatterns.map(p => {
  const found = html.includes(p.pattern);
  return { check: `No ${p.name}`, pass: !found, detail: found ? `Found "${p.pattern}" in page HTML` : 'Clean' };
});

// Check for broken images: <img with empty src or src="#" or src=""
const brokenImgRegex = /<img[^>]*src\s*=\s*["']\s*["'#]/gi;
const brokenImgs = (fetchResult.body || fetchResult.data || '').toString().match(brokenImgRegex);
slopChecks.push({
  check: 'No broken image tags',
  pass: !brokenImgs || brokenImgs.length === 0,
  detail: brokenImgs ? `Found ${brokenImgs.length} broken <img> tag(s)` : 'Clean'
});

// --- SEO checks ---
const fullHtml = (fetchResult.body || fetchResult.data || '').toString();
const seoChecks = [];

// Title tag
const titleMatch = fullHtml.match(/<title[^>]*>([^<]+)<\/title>/i);
seoChecks.push({
  check: 'Title tag exists',
  pass: !!titleMatch && titleMatch[1].trim().length > 0,
  detail: titleMatch ? `Title: "${titleMatch[1].trim().substring(0, 80)}"` : 'Missing <title> tag',
  critical: true
});

// Meta description
const metaDescMatch = fullHtml.match(/<meta[^>]*name\s*=\s*["']description["'][^>]*content\s*=\s*["']([^"']+)["']/i)
  || fullHtml.match(/<meta[^>]*content\s*=\s*["']([^"']+)["'][^>]*name\s*=\s*["']description["']/i);
seoChecks.push({
  check: 'Meta description exists',
  pass: !!metaDescMatch,
  detail: metaDescMatch ? `Description: "${metaDescMatch[1].substring(0, 80)}..."` : 'Missing meta description',
  critical: true
});

// OG image
const ogImageMatch = fullHtml.match(/<meta[^>]*property\s*=\s*["']og:image["'][^>]*>/i);
seoChecks.push({
  check: 'OG image exists',
  pass: !!ogImageMatch,
  detail: ogImageMatch ? 'Found og:image tag' : 'Missing og:image meta tag',
  critical: false
});

// Favicon
const faviconMatch = fullHtml.match(/<link[^>]*rel\s*=\s*["'](icon|shortcut icon|apple-touch-icon)["'][^>]*>/i);
seoChecks.push({
  check: 'Favicon exists',
  pass: !!faviconMatch,
  detail: faviconMatch ? 'Found favicon link' : 'Missing favicon link tag',
  critical: false
});

// Structured data (JSON-LD)
const jsonLdMatch = fullHtml.match(/<script[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>/i);
seoChecks.push({
  check: 'Structured data (JSON-LD) exists',
  pass: !!jsonLdMatch,
  detail: jsonLdMatch ? 'Found JSON-LD structured data' : 'Missing JSON-LD structured data',
  critical: false
});

// H1 tag
const h1Match = fullHtml.match(/<h1[^>]*>/i);
seoChecks.push({
  check: 'At least one H1 tag',
  pass: !!h1Match,
  detail: h1Match ? 'Found H1 tag' : 'Missing H1 tag',
  critical: true
});

return [{ json: { slopChecks, seoChecks } }];

const repoResult = $('Check Repo Exists').first().json;
const claudeWorkflow = $('Check Claude Workflow').first().json;
const claudeMd = $('Check CLAUDE.md').first().json;

const githubChecks = [];

// Repo exists
githubChecks.push({
  check: 'GitHub repo exists',
  pass: !!repoResult.id && !repoResult.message,
  detail: repoResult.id ? `Repo ID: ${repoResult.id}` : (repoResult.message || 'Repo not found'),
  critical: true
});

// Claude workflow exists
githubChecks.push({
  check: 'Claude Code workflow (.github/workflows/claude.yml)',
  pass: !!claudeWorkflow.name && !claudeWorkflow.message,
  detail: claudeWorkflow.name ? 'Found claude.yml' : 'Missing .github/workflows/claude.yml',
  critical: true
});

// CLAUDE.md exists
githubChecks.push({
  check: 'CLAUDE.md exists',
  pass: !!claudeMd.name && !claudeMd.message,
  detail: claudeMd.name ? 'Found CLAUDE.md' : 'Missing CLAUDE.md',
  critical: true
});

return [{ json: { githubChecks } }];

const params = $('Extract Parameters').first().json;
const lighthouse = $('Parse Lighthouse').first().json.lighthouse;
const { slopChecks, seoChecks } = $('Parse HTML Checks').first().json;
const { githubChecks } = $('Parse GitHub Checks').first().json;

const today = new Date().toISOString().split('T')[0];
const allChecks = [];
const failures = [];

// --- Lighthouse ---
if (lighthouse.error) {
  allChecks.push({ category: 'Lighthouse', check: 'Lighthouse Audit', pass: false, detail: lighthouse.error, critical: true });
  failures.push({ category: 'Lighthouse', check: 'Lighthouse Audit', detail: lighthouse.error });
} else {
  const perfPass = lighthouse.performance >= 50;
  const a11yPass = lighthouse.accessibility >= 80;
  const seoPass = lighthouse.seo >= 80;

  allChecks.push({ category: 'Lighthouse', check: 'Performance >= 50', pass: perfPass, detail: `Score: ${lighthouse.performance}`, critical: true });
  allChecks.push({ category: 'Lighthouse', check: 'Accessibility >= 80', pass: a11yPass, detail: `Score: ${lighthouse.accessibility}`, critical: true });
  allChecks.push({ category: 'Lighthouse', check: 'SEO >= 80', pass: seoPass, detail: `Score: ${lighthouse.seo}`, critical: true });

  if (!perfPass) failures.push({ category: 'Lighthouse', check: 'Performance >= 50', detail: `Score: ${lighthouse.performance}` });
  if (!a11yPass) failures.push({ category: 'Lighthouse', check: 'Accessibility >= 80', detail: `Score: ${lighthouse.accessibility}` });
  if (!seoPass) failures.push({ category: 'Lighthouse', check: 'SEO >= 80', detail: `Score: ${lighthouse.seo}` });
}

// --- Slop checks ---
for (const c of slopChecks) {
  allChecks.push({ category: 'Content Quality', ...c, critical: true });
  if (!c.pass) failures.push({ category: 'Content Quality', check: c.check, detail: c.detail });
}

// --- SEO checks ---
for (const c of seoChecks) {
  allChecks.push({ category: 'SEO', ...c });
  if (!c.pass && c.critical) failures.push({ category: 'SEO', check: c.check, detail: c.detail });
}

// --- GitHub checks ---
for (const c of githubChecks) {
  allChecks.push({ category: 'GitHub', ...c });
  if (!c.pass && c.critical) failures.push({ category: 'GitHub', check: c.check, detail: c.detail });
}

// Score
const totalChecks = allChecks.length;
const passedChecks = allChecks.filter(c => c.pass).length;
const criticalFailures = failures.length;
const verdict = criticalFailures === 0 ? 'PASS' : 'FAIL';

// Build report
let report = `# Quality Gate Report: ${params.businessName}\n\n`;
report += `**Date:** ${today}\n`;
report += `**Site:** ${params.siteUrl}\n`;
report += `**Repo:** ShalinPatel670/${params.repoName}\n`;
report += `**Verdict:** ${verdict}\n`;
report += `**Score:** ${passedChecks}/${totalChecks} checks passed\n\n`;

if (lighthouse.performance !== null) {
  report += `## Lighthouse Scores\n`;
  report += `- Performance: ${lighthouse.performance}/100\n`;
  report += `- Accessibility: ${lighthouse.accessibility}/100\n`;
  report += `- SEO: ${lighthouse.seo}/100\n\n`;
}

const categories = ['Lighthouse', 'Content Quality', 'SEO', 'GitHub'];
for (const cat of categories) {
  const catChecks = allChecks.filter(c => c.category === cat);
  if (catChecks.length === 0) continue;
  report += `## ${cat}\n`;
  for (const c of catChecks) {
    report += `- ${c.pass ? 'PASS' : 'FAIL'} | ${c.check} | ${c.detail}\n`;
  }
  report += `\n`;
}

if (failures.length > 0) {
  report += `## Failures Requiring Action\n`;
  for (const f of failures) {
    report += `- [${f.category}] ${f.check}: ${f.detail}\n`;
  }
}

return [{
  json: {
    businessId: params.businessId,
    businessName: params.businessName,
    siteUrl: params.siteUrl,
    repoName: params.repoName,
    verdict,
    passedChecks,
    totalChecks,
    criticalFailures,
    failures,
    report,
    today
  }
}];

const results = $('Aggregate Results').first().json;
const issues = results.failures.map((f, i) => ({
  json: {
    title: `[Quality Gate] ${f.check}`,
    body: `**Category:** ${f.category}\n**Check:** ${f.check}\n**Detail:** ${f.detail}\n\n**Business:** ${results.businessName}\n**Site:** ${results.siteUrl}\n\nThis issue was auto-created by the Pre-Launch Quality Gate workflow.`,
    repoName: results.repoName,
    businessName: results.businessName,
    businessId: results.businessId,
    index: i
  }
}));
return issues;
